using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int n, m, x, a[100005], ans, rf;
map<int, int> mp;
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	cin >> n;
	mp[0] = 0;
	for (int i = 1; i <= n; ++i)
	{
		cin >> a[i];
		rf += a[i] * 2 - 1;
		if (mp.find(rf) == mp.end())
		{
			mp[rf] = i;
		}
		ans = max(ans, i - mp[rf]);
	}
	cout << ans;
	return false;
}
